"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[13542],{42863(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>r,default:()=>c,frontMatter:()=>o,metadata:()=>n,toc:()=>h});let n=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 and IAS 16/lease-term-and-useful-life-of-leaseh-8191c9e768","title":"Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16)","description":"November 2019","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 and IAS 16/Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 16 and IAS 16","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-and-ias-16-0a501fafe8/lease-term-and-useful-life-of-leaseh-8191c9e768","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-and-ias-16-0a501fafe8/lease-term-and-useful-life-of-leaseh-8191c9e768","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":1,"frontMatter":{"id":"lease-term-and-useful-life-of-leaseh-8191c9e768","title":"Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-and-ias-16-0a501fafe8/lease-term-and-useful-life-of-leaseh-8191c9e768","sidebar_position":1},"sidebar":"knowledgeSidebar","previous":{"title":"Subsurface Rights (IFRS 16)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-leases-440a8d9120/subsurface-rights-ifrs-16-2fb78d1eba"},"next":{"title":"Transfer of Insurance Coverage under a Group of Annuity Contracts (IFRS 17)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-17-insurance-contracts-e123436304/transfer-of-insurance-coverage-under-15cb0d63cc"}}');var i=a(74848),s=a(28453);let o={id:"lease-term-and-useful-life-of-leaseh-8191c9e768",title:"Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-16-and-ias-16-0a501fafe8/lease-term-and-useful-life-of-leaseh-8191c9e768",sidebar_position:1},r="Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16)",l={},h=[{value:"Lease term",id:"lease-term",level:2},{value:"Useful life of non-removable leasehold improvements",id:"useful-life-of-non-removable-leasehold-improvements",level:2},{value:"Interaction between lease term and useful life",id:"interaction-between-lease-term-and-useful-life",level:2}];function d(e){let t={h1:"h1",h2:"h2",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,i.jsxs)(i.Fragment,{children:[(0,i.jsx)(t.header,{children:(0,i.jsx)(t.h1,{id:"lease-term-and-useful-life-of-leasehold-improvements-ifrs-16-and-ias-16",children:"Lease Term and Useful Life of Leasehold Improvements (IFRS 16 and IAS 16)"})}),"\n",(0,i.jsx)(t.p,{children:"November 2019"}),"\n",(0,i.jsx)(t.p,{children:"The Committee received a request about cancellable or renewable leases."}),"\n",(0,i.jsx)(t.p,{children:"The cancellable lease described in the request is one that does not specify a particular contractual term but continues indefinitely until either party to the contract gives notice to terminate. The contract includes a notice period of, for example, less than 12 months and the contract does not oblige either party to make a payment on termination. The renewable lease described in the request is one that specifies an initial period, and renews indefinitely at the end of the initial period unless terminated by either of the parties to the contract."}),"\n",(0,i.jsx)(t.p,{children:"The request asked two questions:"}),"\n",(0,i.jsx)(t.p,{children:"a. how to determine the lease term of a cancellable lease or a renewable lease. Specifically, the request asked whether, when applying paragraph B34 of IFRS 16 and assessing \u2018no more than an insignificant penalty\u2019, an entity considers the broader economics of the contract, and not only contractual termination payments. Such considerations might include, for example, the cost of abandoning or dismantling leasehold improvements.\nb. whether the useful life of any related non-removable leasehold improvements is limited to the lease term determined applying IFRS 16. Non-removable leasehold improvements are, for example, fixtures and fittings acquired by the lessee and constructed on the underlying asset that is the subject of the cancellable or renewable lease. The lessee will use and benefit from the leasehold improvements only for as long as it uses the underlying asset."}),"\n",(0,i.jsx)(t.h2,{id:"lease-term",children:"Lease term"}),"\n",(0,i.jsx)(t.p,{children:"Paragraph 18 of IFRS 16 requires an entity to determine the lease term as the non-cancellable period of a lease, together with both (a) periods covered by an option to extend the lease if the lessee is reasonably certain to exercise that option; and (b) periods covered by an option to terminate the lease if the lessee is reasonably certain not to exercise that option."}),"\n",(0,i.jsx)(t.p,{children:"In determining the lease term and assessing the length of the non-cancellable period of a lease, paragraph B34 of IFRS 16 requires an entity to determine the period for which the contract is enforceable. Paragraph B34 specifies that \u2018a lease is no longer enforceable when the lessee and the lessor each has the right to terminate the lease without permission from the other party with no more than an insignificant penalty\u2019."}),"\n",(0,i.jsx)(t.p,{children:"Paragraph BC156 sets out the Board\u2019s view that \u2018the lease term should reflect an entity\u2019s reasonable expectation of the period during which the underlying asset will be used because that approach provides the most useful information\u2019."}),"\n",(0,i.jsx)(t.p,{children:"The Committee observed that, in applying paragraph B34 and determining the enforceable period of the lease described in the request, an entity considers:"}),"\n",(0,i.jsx)(t.p,{children:"a. the broader economics of the contract, and not only contractual termination payments. For example, if either party has an economic incentive not to\nterminate the lease such that it would incur a penalty on termination that is more than insignificant, the contract is enforceable beyond the date on which the contract can be terminated; and\nb. whether each of the parties has the right to terminate the lease without permission from the other party with no more than an insignificant penalty. Applying paragraph B34, a lease is no longer enforceable only when both parties have such a right. Consequently, if only one party has the right to terminate the lease without permission from the other party with no more than an insignificant penalty, the contract is enforceable beyond the date on which the contract can be terminated by that party."}),"\n",(0,i.jsx)(t.p,{children:"If an entity concludes that the contract is enforceable beyond the notice period of a cancellable lease (or the initial period of a renewable lease), it then applies paragraphs 19 and B37\u2013B40 of IFRS 16 to assess whether the lessee is reasonably certain not to exercise the option to terminate the lease."}),"\n",(0,i.jsx)(t.h2,{id:"useful-life-of-non-removable-leasehold-improvements",children:"Useful life of non-removable leasehold improvements"}),"\n",(0,i.jsx)(t.p,{children:"Paragraph 50 of IAS 16 requires an item of property, plant and equipment (asset) to be depreciated over its useful life."}),"\n",(0,i.jsx)(t.p,{children:"IAS 16 defines the useful life of an asset as (emphasis added) \u2018the period over which an asset is expected to be available for use by an entity; or the number of production or similar units expected to be obtained from the asset by an entity\u2019."}),"\n",(0,i.jsx)(t.p,{children:"Paragraphs 56 and 57 of IAS 16 provide further requirements on the useful life of an asset. In particular, paragraph 56(d) specifies that in determining the useful life of an asset, an entity considers any \u2018legal or similar limits on the use of the asset, such as the expiry dates of related leases\u2019. Paragraph 57 specifies that the useful life of an asset \u2018is defined in terms of the asset\u2019s expected utility to the entity\u2019, and \u2018may be shorter than its economic life\u2019."}),"\n",(0,i.jsx)(t.p,{children:"An entity applies paragraphs 56\u201357 of IAS 16 in determining the useful life of non-removable leasehold improvements. If the lease term of the related lease is shorter than the economic life of those leasehold improvements, the entity considers whether it expects to use the leasehold improvements beyond that lease term. If the entity does not expect to use the leasehold improvements beyond the lease term of the related lease then, applying paragraph 57 of IAS 16, it concludes that the useful life of the non-removable leasehold improvements is the same as the lease term. The Committee observed that, applying paragraphs 56\u201357 of IAS 16, an entity might often reach this conclusion for leasehold improvements that the entity will use and benefit from only for as long as it uses the underlying asset in the lease."}),"\n",(0,i.jsx)(t.h2,{id:"interaction-between-lease-term-and-useful-life",children:"Interaction between lease term and useful life"}),"\n",(0,i.jsx)(t.p,{children:"In assessing whether a lessee is reasonably certain to extend (or not to terminate) a lease, paragraph B37 of IFRS 16 requires an entity to consider all relevant facts and circumstances that create an economic incentive for the lessee. This includes significant leasehold improvements undertaken (or expected to be undertaken) over the term of the contract that are expected to have significant economic benefit for the lessee when an option to extend or terminate the lease becomes exercisable (paragraph B37(b))."}),"\n",(0,i.jsx)(t.p,{children:"In addition, as noted above an entity considers the broader economics of the contract when determining the enforceable period of the lease described in the request. This includes, for example, the costs of abandoning or dismantling non-removable leasehold improvements. If an entity expects to use non-removable leasehold improvements beyond the date on which the contract can be terminated, the existence of those leasehold improvements indicates that the entity might incur a more than insignificant penalty if it terminates the lease. Consequently, applying paragraph B34 of IFRS 16, an\nentity considers whether the contract is enforceable for at least the period of expected utility of the leasehold improvements."}),"\n",(0,i.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS 16 provide an adequate basis for an entity to determine the lease term of cancellable and renewable leases. The Committee also concluded that the principles and requirements in IAS 16 and IFRS 16 provide an adequate basis for an entity to determine the useful life of any non-removable leasehold improvements relating to such a lease. Consequently, the Committee decided not to add the matter to its standard-setting agenda."})]})}function c(e={}){let{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,i.jsx)(t,{...e,children:(0,i.jsx)(d,{...e})}):d(e)}},28453(e,t,a){a.d(t,{R:()=>o,x:()=>r});var n=a(96540);let i={},s=n.createContext(i);function o(e){let t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:o(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);